AppRoutePath parseAppRoute(Uri uri) {
  final segments = uri.pathSegments;

  if (segments.isEmpty) {
    return DashboardRoute();
  }

  if (segments.length == 1 && segments[0] == '404') {
    return NotFoundRoute(path: uri.queryParameters['path'] ?? '');
  }

  if (segments.length == 1 && segments[0] == 'admin') {
    return AdminRoute();
  }

  if (segments.length == 3 &&
      segments[0] == 'billing' &&
      segments[1] == 'invoices') {
    final invoiceId = segments[2];
    return InvoiceRoute(
      invoiceId: invoiceId,
      download: _parseBool(uri.queryParameters['download']) ?? false,
    );
  }

  if (segments.length == 2 && segments[0] == 'checkout') {
    final plan = segments[1];
    return CheckoutRoute(
      plan: plan,
      annual: _parseBool(uri.queryParameters['annual']) ?? false,
    );
  }

  if (segments.length == 1 && segments[0] == 'forbidden') {
    return ForbiddenRoute();
  }

  if (segments.length == 2 && segments[0] == 'invite') {
    final token = segments[1];
    return InviteRoute(token: token);
  }

  if (segments.length == 1 && segments[0] == 'login') {
    return LoginRoute(from: uri.queryParameters['from']);
  }

  if (segments.length == 2 && segments[0] == 'posts') {
    final id = int.tryParse(segments[1]);
    if (id == null) {
      return _notFoundRoute(uri);
    }
    return PostDetailRoute(id: id);
  }

  if (segments.length == 2 && segments[0] == 'projects') {
    final projectId = int.tryParse(segments[1]);
    if (projectId == null) {
      return _notFoundRoute(uri);
    }
    return ProjectRoute(projectId: projectId, tab: uri.queryParameters['tab']);
  }

  if (segments.length == 3 &&
      segments[0] == 'projects' &&
      segments[2] == 'settings') {
    final projectId = int.tryParse(segments[1]);
    if (projectId == null) {
      return _notFoundRoute(uri);
    }
    return ProjectSettingsRoute(
      projectId: projectId,
      section: uri.queryParameters['section'] ?? 'general',
    );
  }

  if (segments.length == 1 && segments[0] == 'search') {
    return SearchRoute(
      q: uri.queryParameters['q'],
      page: int.tryParse(uri.queryParameters['page'] ?? '') ?? 1,
    );
  }

  return _notFoundRoute(uri);
}

AppRoutePath _notFoundRoute(Uri uri) => NotFoundRoute(path: uri.toString());

bool? _parseBool(String? value) {
  return switch (value) {
    'true' || '1' => true,
    'false' || '0' => false,
    null || '' => null,
    _ => () {
      assert(
        false,
        '_parseBool: unrecognised value "$value", treating as null',
      );
      return null;
    }(),
  };
}

